// RequestVideoUpload is the resolver for the requestVideoUpload field.
func (r *mutationResolver) RequestVideoUpload(ctx context.Context, input model.UploadVideoInput) (*model.UploadResponse, error) {
	// 0. Check limit
	var count int
	r.DB.Pool.QueryRow(ctx, "SELECT count(*) FROM videos").Scan(&count)
	if count >= 2 {
		return nil, fmt.Errorf("upload limit reached: maximum 2 videos allowed")
	}

	// 1. Insert into DB to get ID
	var id string
	err := r.DB.Pool.QueryRow(ctx, "INSERT INTO videos (title, s3_key, status) VALUES ($1, $2, 'uploading') RETURNING id::text", input.Title, "pending").Scan(&id)
	if err != nil {
		return nil, fmt.Errorf("failed to create video record: %w", err)
	}

	// 2. Generate S3 key
	s3Key := fmt.Sprintf("raw/%s_%s", id, input.Filename)

	// Update the s3_key in DB
	_, err = r.DB.Pool.Exec(ctx, "UPDATE videos SET s3_key = $1 WHERE id = $2", s3Key, id)
	if err != nil {
		return nil, fmt.Errorf("failed to update s3 key: %w", err)
	}

	// 3. Generate presigned URL
	url, err := r.S3Client.GeneratePresignedUploadURL(ctx, s3Key, 15*time.Minute)
	if err != nil {
		return nil, err
	}

	return &model.UploadResponse{
		UploadURL: url,
		VideoID:   id,
		S3Key:     s3Key,
	}, nil
}

// FinalizeVideoUpload is the resolver for the finalizeVideoUpload field.
func (r *mutationResolver) FinalizeVideoUpload(ctx context.Context, input model.FinalizeVideoInput) (*model.Video, error) {
	var v model.Video
	var summary *string
	var createdAt time.Time
	err := r.DB.Pool.QueryRow(ctx, "UPDATE videos SET status = 'processing' WHERE id = $1 RETURNING id::text, title, s3_key, status, summary, created_at", input.VideoID).
		Scan(&v.ID, &v.Title, &v.S3Key, &v.Status, &summary, &createdAt)
	if err != nil {
		return nil, err
	}
	v.CreatedAt = createdAt.Format(time.RFC3339)
	if summary != nil {
		v.Summary = summary
	}

	// Produce to Kafka
	event := worker.ProcessVideoEvent{
		VideoID: v.ID,
		S3Key:   v.S3Key,
	}
	r.Producer.ProduceEvent(ctx, v.ID, event)

	return &v, nil
}

