// DeleteVideo is the resolver for the deleteVideo field.
func (r *mutationResolver) DeleteVideo(ctx context.Context, videoID string) (bool, error) {
	// 1. Get S3 key
	var s3Key string
	err := r.DB.Pool.QueryRow(ctx, "SELECT s3_key FROM videos WHERE id = $1", videoID).Scan(&s3Key)
	if err != nil {
		return false, fmt.Errorf("video not found: %w", err)
	}

	// 2. Delete from S3 (if not youtube link)
	if s3Key != "" && s3Key[:4] != "http" {
		_ = r.S3Client.DeleteFile(ctx, s3Key)
	}

	// 3. Delete from DB
	_, _ = r.DB.Pool.Exec(ctx, "DELETE FROM visual_chunks WHERE video_id = $1", videoID)
	_, _ = r.DB.Pool.Exec(ctx, "DELETE FROM transcript_chunks WHERE video_id = $1", videoID)
	_, err = r.DB.Pool.Exec(ctx, "DELETE FROM videos WHERE id = $1", videoID)
	if err != nil {
		return false, fmt.Errorf("failed to delete video record: %w", err)
	}

	return true, nil
}

